import React, { useState } from "react";
import axios from "axios";
import "./ChatBox.css";
import MapView from "./MapView";

function ChatBox() {

  const [query, setQuery] = useState("");
  const [persons, setPersons] = useState(1);

  const [response, setResponse] = useState({
    ai_response: "",
    budget: {},
    recommendations: [],
    safety: {},
    itinerary: [],
    destination_map: null
  });

  const sendQuery = async () => {

    if (!query) {
      alert("Please enter trip details");
      return;
    }

    try {

      const res = await axios.post(
        "http://127.0.0.1:8000/chat",
        {
          query,
          persons: Number(persons)
        }
      );

      setResponse({
        ai_response: res.data.ai_response || "",
        budget: res.data.budget || {},
        recommendations: res.data.recommendations || [],
        safety: res.data.safety || {},
        itinerary: res.data.itinerary || [],
        destination_map: res.data.destination_map || null
      });

    } catch (error) {

      console.log(error);

      alert("Backend connection failed");
    }
  };

  return (

    <div className="container">

      <h1>🇮🇳 India AI Travel Planner</h1>

      <p className="subtitle">
        Plan your budget-friendly India trip with AI recommendations,
        nearby places, safety analysis and map integration.
      </p>

      <textarea
        placeholder="Example: Plan 3 days Goa trip under 20000"
        value={query}
        onChange={(e) => setQuery(e.target.value)}
      />

      <div className="input-group">

        <input
          type="number"
          min="1"
          value={persons}
          onChange={(e) => setPersons(e.target.value)}
          placeholder="Persons"
        />

        <button onClick={sendQuery}>
          Plan Trip
        </button>

      </div>

      <div className="response">

        <h2>🤖 AI Response</h2>

        <p>{response.ai_response}</p>

        {/* Budget */}

        <h2>💰 Budget Details</h2>

        <div className="budget-box">

          <p>🏨 Hotel Cost: ₹{response.budget.hotel || 0}</p>

          <p>🍛 Food Cost: ₹{response.budget.food || 0}</p>

          <p>🚌 Transport Cost: ₹{response.budget.transport || 0}</p>

          <h3>Total Budget: ₹{response.budget.total || 0}</h3>

        </div>

        {/* Recommended Places */}

        <h2>📍 Nearby Recommended Places</h2>

        {
          response.recommendations.length > 0 ? (

            response.recommendations.map((place, index) => (

              <div className="card" key={index}>

                <h3>{place.name}</h3>

                <p><b>City:</b> {place.city}</p>

                <p><b>State:</b> {place.state}</p>

                <p><b>Type:</b> {place.type}</p>

                <p><b>Budget:</b> ₹{place.total_budget}</p>

                <p><b>Women Safety:</b> {place.women_safe}</p>

                <p><b>Safety Score:</b> {place.safety_score}</p>

                <p><b>Crowd Level:</b> {place.crowd_level}</p>

                <p><b>Best Time:</b> {place.best_time}</p>

                <p><b>Nearby Good Place:</b> {place.good_place}</p>

                <p><b>Avoid Area:</b> {place.bad_place}</p>

                <hr />

                <p>🚆 Railway Station: {place.railway_distance} km</p>

                <p>🚌 Bus Stand: {place.bus_distance} km</p>

                <p>✈ Airport: {place.airport_distance} km</p>

              </div>

            ))

          ) : (

            <p>No recommendations available</p>

          )
        }

        {/* Single Map */}

        <h2>🗺 Destination Map</h2>

        {
          response.destination_map && (

            <MapView
              lat={response.destination_map.lat}
              lng={response.destination_map.lng}
              name={response.destination_map.name}
            />

          )
        }

        {/* Safety */}

        <h2>🛡 Safety Information</h2>

        <div className="safety-box">

          <p>
            <b>Women Safety:</b>
            {" "}
            {response.safety.women_safety || "Moderate"}
          </p>

          <p>
            <b>Child Friendly:</b>
            {" "}
            {response.safety.child_friendly || "Yes"}
          </p>

          <p>
            <b>Night Travel Risk:</b>
            {" "}
            {response.safety.night_risk || "Low"}
          </p>

        </div>

        {/* Itinerary */}

        <h2>🗓 Trip Itinerary</h2>

        {
          response.itinerary.length > 0 ? (

            response.itinerary.map((day, index) => (

              <div className="itinerary-day" key={index}>
                {day}
              </div>

            ))

          ) : (

            <p>No itinerary available</p>

          )
        }

      </div>

    </div>
  );
}

export default ChatBox;
